// CUSTOMIZE: This is the static, hand-scripted data that powers the
// credential-free NEXT_PUBLIC_REPLAY_MODE=1 deploy (e.g. the public Vercel
// build) -- every event, timestamp, and provider comparison below is fixed
// ahead of time, not generated by a live agent or LLM call. If you're
// adapting this template to your own agent/scenario, replace the contents
// of this file (REPLAY_BEATS, the provider candidates, REPLAY_KICKOFF_PROMPT,
// etc.) with data that matches your own agent's actual flow -- lib/useReplay.ts
// just plays back whatever beats/events you put here, so it doesn't need to
// change.
//
// Static data for the public "replay" site (NEXT_PUBLIC_REPLAY_MODE=1).
// Per the original design decision: the public site plays back a fixed,
// recorded-shaped run rather than exposing a live "Run Live" button to
// anonymous visitors against a real or mutable-in-memory backend. This file
// is the single source of truth for that run -- no server state, no API
// calls, safe to deploy to Vercel's serverless functions (which don't
// guarantee shared memory across invocations the way `next dev`'s single
// process does).
//
// Scenario: an enterprise support/trust-and-safety agent triages flagged
// tickets during the day -- verifying details via real x402-payable research
// APIs, and placing a real x402-payable phone call when warranted. Every
// provider below is real and independently confirmed to support x402
// payments: Tavily (docs.tavily.com/documentation/machine-payments/x402),
// Parallel.ai (parallelmpp.dev), and StablePhone (stablephone.dev, real
// disclosed price of $0.54/call). The one illustrative price is
// StablePhone's "priority" human-transfer tier -- that specific tiered price
// isn't publicly disclosed, so it's a reconstruction on the same real host,
// same disclosure convention as everything else illustrative in this file.
//
// The whole run is stamped onto a single mocked calendar day (2026-07-08,
// 9am-10pm) rather than "just now" timestamps, so the Activity Feed and Audit
// Trail read as a realistic day of a periodic monitoring agent's activity
// instead of a few seconds of wall-clock time.
import type { LedgerEntry } from "./t3n";

export interface ProviderCandidate {
  host: string;
  provider: string;
  category: string;
  /** omitted for candidates that can't actually be paid -- see `ineligible` */
  price?: number;
  /** true if the agent ruled this one out before pricing even mattered (e.g. no x402 support) */
  ineligible?: boolean;
  ineligibleReason?: string;
}

export interface ReplayEvent {
  ts: string; // ISO timestamp on the mocked replay day, always rendered in UTC
  type: "thinking" | "tool_call" | "tool_result" | "comparing_providers" | "payment_approved" | "payment_denied" | "user_reply";
  candidates?: ProviderCandidate[];
  selectedHost?: string;
  reason?: string;
  /** true on the first event after a visitor clicks Revoke -- lets the chat panel surface it as an operator action. */
  revokedNotice?: boolean;
  [key: string]: unknown;
}

export interface ReplayBeat {
  narration: string;
  events: ReplayEvent[];
  /** ms to hold after this beat's events finish, before the next beat starts */
  holdMs: number;
  /** if true, playback stops after this beat until the visitor clicks to continue */
  pauseForRevoke?: boolean;
}

const REPLAY_DAY = "2026-07-08";
const t = (time: string) => `${REPLAY_DAY}T${time}.000Z`;

const TAVILY_URL = "https://api.tavily.com/search";
const PARALLEL_URL = "https://api.parallel.ai/v1beta/tasks/runs";
const STABLEPHONE_URL = "https://stablephone.dev/api/v1/call";
// Illustrative -- same real host/provider as STABLEPHONE_URL, but the
// human-transfer "priority" tier's exact price isn't publicly disclosed.
const STABLEPHONE_PRIORITY_URL = "https://stablephone.dev/api/v1/call/priority";

// Officially reserved fictional US phone number range (555-0100 to
// 555-0199) -- guarantees nothing in this replay implies a real number is
// ever dialed.
const FAKE_PHONE_NUMBER = "+1-555-0142";

const TAVILY: ProviderCandidate = { host: "api.tavily.com", provider: "Tavily", category: "WEB_RESEARCH", price: 0.015 };
const PARALLEL: ProviderCandidate = { host: "api.parallel.ai", provider: "Parallel", category: "WEB_RESEARCH", price: 0.018 };
const STABLEPHONE: ProviderCandidate = { host: "stablephone.dev", provider: "StablePhone", category: "COMMUNICATIONS", price: 0.54 };
// Twilio is a real voice API, but it has no x402 support -- there's no way
// for an autonomous agent wallet to pay it per call, only pre-provisioned
// account billing. It's shown ruled out, not priced, since price was never
// the deciding factor.
const TWILIO: ProviderCandidate = {
  host: "twilio.com",
  provider: "Twilio",
  category: "COMMUNICATIONS",
  ineligible: true,
  ineligibleReason: "No x402 support",
};

export const REPLAY_POLICY = {
  per_call_cap: 0.6,
  session_budget: 1.0,
  host_allowlist: ["api.tavily.com", "api.parallel.ai", "stablephone.dev"],
};

