// The timestamp stamped on the visitor's own kickoff message -- same moment
// as the agent's first scheduled check-in, since nothing happens until they
// send it.
export const REPLAY_KICKOFF_TS = REPLAY_BEATS[0].events[0].ts;

export function ledgerEntryFromEvent(event: ReplayEvent, seq: number): LedgerEntry | null {
  if (event.type !== "payment_approved" && event.type !== "payment_denied") return null;
  return {
    seq,
    ts: new Date(event.ts).getTime(),
    service_url: String(event.service_url ?? ""),
    amount_usdc: Number(event.amount_usdc ?? 0),
    status: event.type === "payment_approved" ? "paid" : "denied",
    reason: event.reason ? String(event.reason) : undefined,
    remaining_budget: event.remaining_budget !== undefined ? Number(event.remaining_budget) : undefined,
    idempotency_key: `replay-${seq}`,
  };
}
